/**
 * Expected form field names:
 *   videoUrl
 *   textUrl
 *   variant
 *   language
 *   voice
 *   recipientEmail
 */

const ALLOWED_VARIANTS = new Set([
  'full',
  'voiceover',
  'subtitles',
  'dubbed',
  'subtitled',
]);

const ALLOWED_LANGUAGES = new Set([
  'pl',
  'en',
]);

const ALLOWED_VOICES = new Set([
  'pl-PL-ZofiaNeural',
  'pl-PL-MarekNeural',
  'en-US-JennyNeural',
  'en-US-GuyNeural',
]);

const GOOGLE_FILE_ID_PATTERN = /^[A-Za-z0-9_-]{10,}$/;
const EMAIL_PATTERN = /^[^\s@]+@[^\s@]+\.[^\s@]{2,}$/i;
const HTTPS_URL_PATTERN = /^https:\/\/([^/?#]+)([^?#]*)(?:\?([^#]*))?(?:#.*)?$/i;

function addError(errors, field, code, message) {
  errors.push({
    field,
    code,
    message,
  });
}

function getRequiredString(input, field, errors, options = {}) {
  const label = options.label ?? field;
  const maxLength = options.maxLength ?? 2048;
  const value = input[field];

  if (typeof value !== 'string') {
    addError(
      errors,
      field,
      'INVALID_TYPE',
      `Pole "${label}" musi być tekstem.`,
    );

    return null;
  }

  const normalizedValue = value.trim();

  if (normalizedValue.length === 0) {
    addError(
      errors,
      field,
      'REQUIRED',
      `Pole "${label}" jest wymagane.`,
    );

    return null;
  }

  if (normalizedValue.length > maxLength) {
    addError(
      errors,
      field,
      'TOO_LONG',
      `Pole "${label}" może mieć maksymalnie ${maxLength} znaków.`,
    );

    return null;
  }

  return normalizedValue;
}

function getQueryParameter(queryString, parameterName) {
  if (!queryString) {
    return null;
  }

  const pairs = queryString.split('&');

  for (const pair of pairs) {
    const separatorIndex = pair.indexOf('=');

    const rawKey =
      separatorIndex === -1
        ? pair
        : pair.slice(0, separatorIndex);

    if (decodeURIComponent(rawKey.replace(/\+/g, ' ')) !== parameterName) {
      continue;
    }

    const rawValue =
      separatorIndex === -1
        ? ''
        : pair.slice(separatorIndex + 1);

    return decodeURIComponent(rawValue.replace(/\+/g, ' '));
  }

  return null;
}

function parseHttpsUrl(value, field, errors) {
  const match = value.match(HTTPS_URL_PATTERN);

  if (!match) {
    addError(
      errors,
      field,
      'INVALID_URL',
      'Podaj prawidłowy link HTTPS.',
    );

    return null;
  }

  const hostname = (match[1] ?? '')
    .toLowerCase()
    .replace(/^www\./, '');

  const pathname = match[2] || '/';
  const queryString = match[3] || '';

  return {
    hostname,
    pathname,
    queryString,
  };
}

function validateGoogleResourceUrl(
  value,
  field,
  errors,
  acceptedResourceTypes,
) {
  const parsedUrl = parseHttpsUrl(value, field, errors);

  if (parsedUrl === null) {
    return null;
  }

  const {
    hostname,
    pathname,
    queryString,
  } = parsedUrl;

  let resourceId = null;
  let resourceType = null;

  if (hostname === 'drive.google.com') {
    if (/\/folders\//i.test(pathname)) {
      addError(
        errors,
        field,
        'FOLDER_NOT_ALLOWED',
        'Podaj link do pliku, a nie do folderu Google Drive.',
      );

      return null;
    }

    const filePathMatch = pathname.match(
      /\/file\/d\/([A-Za-z0-9_-]+)/i,
    );

    resourceId =
      filePathMatch?.[1] ??
      getQueryParameter(queryString, 'id');

    resourceType = 'driveFile';
  } else if (hostname === 'docs.google.com') {
    const documentMatch = pathname.match(
      /\/document\/d\/([A-Za-z0-9_-]+)/i,
    );

    if (documentMatch?.[1]) {
      resourceId = documentMatch[1];
      resourceType = 'googleDocument';
    }
  } else {
    addError(
      errors,
      field,
      'INVALID_GOOGLE_DOMAIN',
      'Dozwolone są wyłącznie linki z drive.google.com lub docs.google.com.',
    );

    return null;
  }

  if (
    resourceId === null ||
    !GOOGLE_FILE_ID_PATTERN.test(resourceId)
  ) {
    addError(
      errors,
      field,
      'INVALID_GOOGLE_RESOURCE',
      'Nie udało się odczytać prawidłowego identyfikatora pliku Google.',
    );

    return null;
  }

  if (
    resourceType === null ||
    !acceptedResourceTypes.includes(resourceType)
  ) {
    addError(
      errors,
      field,
      'UNSUPPORTED_GOOGLE_RESOURCE',
      'Ten typ zasobu Google nie jest obsługiwany w tym polu.',
    );

    return null;
  }

  const canonicalUrl =
    resourceType === 'googleDocument'
      ? `https://docs.google.com/document/d/${resourceId}/edit`
      : `https://drive.google.com/file/d/${resourceId}/view`;

  return {
    id: resourceId,
    type: resourceType,
    url: canonicalUrl,
  };
}

function validateEnum(
  value,
  field,
  label,
  errors,
  allowedValues,
) {
  if (value === null) {
    return null;
  }

  if (!allowedValues.has(value)) {
    addError(
      errors,
      field,
      'INVALID_VALUE',
      `Pole "${label}" zawiera nieobsługiwaną wartość: "${value}".`,
    );

    return null;
  }

  return value;
}

function validateEmail(value, errors) {
  if (value === null) {
    return null;
  }

  const normalizedEmail = value.toLowerCase();

  if (!EMAIL_PATTERN.test(normalizedEmail)) {
    addError(
      errors,
      'recipientEmail',
      'INVALID_EMAIL',
      'Podaj prawidłowy adres email.',
    );

    return null;
  }

  return normalizedEmail;
}

const items = $input.all();

return items.map((item, index) => {
  const input = item.json ?? {};
  const errors = [];

  const videoUrlValue = getRequiredString(
    input,
    'videoUrl',
    errors,
    {
      label: 'Video URL',
      maxLength: 2048,
    },
  );

  const textUrlValue = getRequiredString(
    input,
    'textUrl',
    errors,
    {
      label: 'Text URL',
      maxLength: 2048,
    },
  );

  const variantValue = getRequiredString(
    input,
    'variant',
    errors,
    {
      label: 'Variant',
      maxLength: 50,
    },
  );

  const languageValue = getRequiredString(
    input,
    'language',
    errors,
    {
      label: 'Language',
      maxLength: 10,
    },
  );

  const voiceValue = getRequiredString(
    input,
    'voice',
    errors,
    {
      label: 'Voice',
      maxLength: 100,
    },
  );

  const recipientEmailValue = getRequiredString(
    input,
    'recipientEmail',
    errors,
    {
      label: 'Recipient Email',
      maxLength: 254,
    },
  );

  const variant = validateEnum(
    variantValue?.toLowerCase() ?? null,
    'variant',
    'Variant',
    errors,
    ALLOWED_VARIANTS,
  );

  const language = validateEnum(
    languageValue?.toLowerCase() ?? null,
    'language',
    'Language',
    errors,
    ALLOWED_LANGUAGES,
  );

  const voice = validateEnum(
    voiceValue,
    'voice',
    'Voice',
    errors,
    ALLOWED_VOICES,
  );

  const recipientEmail = validateEmail(
    recipientEmailValue,
    errors,
  );

  let videoResource = null;
  let textResource = null;

  if (videoUrlValue !== null) {
    videoResource = validateGoogleResourceUrl(
      videoUrlValue,
      'videoUrl',
      errors,
      ['driveFile'],
    );
  }

  if (textUrlValue !== null) {
    textResource = validateGoogleResourceUrl(
      textUrlValue,
      'textUrl',
      errors,
      [
        'driveFile',
        'googleDocument',
      ],
    );
  }

  if (
    language !== null &&
    voice !== null &&
    !voice.toLowerCase().startsWith(`${language}-`)
  ) {
    addError(
      errors,
      'voice',
      'VOICE_LANGUAGE_MISMATCH',
      `Wybrany głos "${voice}" nie pasuje do języka "${language}".`,
    );
  }

  let data = null;

  if (
    errors.length === 0 &&
    videoResource !== null &&
    textResource !== null &&
    variant !== null &&
    language !== null &&
    voice !== null &&
    recipientEmail !== null
  ) {
    data = {
      videoUrl: videoResource.url,
      videoFileId: videoResource.id,

      textUrl: textResource.url,
      textFileId: textResource.id,
      textSourceType: textResource.type,

      variant,
      language,
      voice,
      recipientEmail,
    };
  }

  const valid = data !== null;

  return {
    json: {
      valid,
      statusCode: valid ? 200 : 400,
      message: valid
        ? 'Dane formularza są prawidłowe.'
        : 'Walidacja formularza nie powiodła się.',
      errors,
      data,
    },
    pairedItem: {
      item: index,
    },
  };
});

