const items = $input.all().map((item) => item.json);

const video = items.find((item) => item.video)?.video ?? null;
const text = items.find((item) => item.text)?.text ?? null;

const errors = [];

function addError(field, code, message) {
  errors.push({
    field,
    code,
    message,
  });
}

// Walidacja filmu
if (!video) {
  addError(
    'videoUrl',
    'VIDEO_METADATA_MISSING',
    'Nie udało się pobrać informacji o pliku wideo.',
  );
} else {
  if (video.trashed !== false) {
    addError(
      'videoUrl',
      'FILE_IN_TRASH',
      'Wybrany plik wideo znajduje się w koszu.',
    );
  }

  if (
    typeof video.mimeType !== 'string' ||
    !video.mimeType.startsWith('video/')
  ) {
    addError(
      'videoUrl',
      'INVALID_VIDEO_MIME_TYPE',
      `Wybrany plik nie jest plikiem wideo. Wykryty typ: ${
        video.mimeType ?? 'nieznany'
      }.`,
    );
  }
}

// Dozwolone typy pliku tekstowego
const allowedTextMimeTypes = new Set([
  'text/plain',
]);

// Walidacja tekstu
if (!text) {
  addError(
    'textUrl',
    'TEXT_METADATA_MISSING',
    'Nie udało się pobrać informacji o pliku tekstowym.',
  );
} else {
  if (text.trashed !== false) {
    addError(
      'textUrl',
      'FILE_IN_TRASH',
      'Wybrany plik tekstowy znajduje się w koszu.',
    );
  }

  if (!allowedTextMimeTypes.has(text.mimeType)) {
    addError(
      'textUrl',
      'INVALID_TEXT_MIME_TYPE',
      `Wybrany plik nie jest obsługiwanym plikiem tekstowym. Wykryty typ: ${
        text.mimeType ?? 'nieznany'
      }.`,
    );
  }
}

const valid = errors.length === 0;

// Dane z wcześniejszej walidacji formularza
const formData = $('Is Input Valid?').first().json.data ?? null;

return [
  {
    json: {
      valid,
      statusCode: valid ? 200 : 400,
      message: valid
        ? 'Pliki Google Drive są prawidłowe.'
        : 'Walidacja plików Google Drive nie powiodła się.',
      errors,
      data: valid
        ? {
            ...formData,
            video,
            text,
          }
        : null,
    },
  },
];

